from datetime import datetime
from typing import Optional

class ContextWindowManager:
    """Manages context window for cricket match analysis agent."""

    def __init__(self, max_window_tokens: int = 4000):
        self.max_window_tokens = max_window_tokens
        self.message_history = []
        self.summary_checkpoint = None

    def add_message(self, role: str, content: str, innings: int):
        """Add message with metadata (e.g., innings number)."""
        self.message_history.append({
            'role': role,
            'content': content,
            'innings': innings,
            'timestamp': datetime.now()
        })
        self._check_and_summarize()

    def _estimate_tokens(self, text: str) -> int:
        """Rough token estimation (1 word ≈ 1.3 tokens)."""
        return int(len(text.split()) * 1.3)

    def _check_and_summarize(self):
        """Trigger summarization when window exceeds threshold."""
        total_tokens = sum(
            self._estimate_tokens(msg['content']) 
            for msg in self.message_history
        )

        if total_tokens > self.max_window_tokens:
            self._create_summary()

    def _create_summary(self):
        """Compress old messages into structured summary."""
        # Group by innings (cricket metaphor)
        innings_data = {}
        for msg in self.message_history[:-5]:  # Keep last 5 recent
            innings = msg['innings']
            if innings not in innings_data:
                innings_data[innings] = []
            innings_data[innings].append(msg['content'])

        # Create compressed summary
        summary = "SUMMARIZED CONTEXT: "
        for innings, contents in innings_data.items():
            key_facts = ' '.join(contents)[:200]  # Truncate
            summary += f"Innings {innings}: {key_facts}... | "

        self.summary_checkpoint = {
            'summary': summary,
            'timestamp': datetime.now()
        }

        # Keep only recent messages + summary
        self.message_history = [
            {'role': 'system', 'content': summary}
        ] + self.message_history[-5:]

    def get_context_for_agent(self) -> list:
        """Return optimized context window for agent inference."""
        if self.summary_checkpoint:
            return [
                self.summary_checkpoint,
                *self.message_history
            ]
        return self.message_history

# Usage example
manager = ContextWindowManager(max_window_tokens=4000)
manager.add_message('user', 'India won by 50 runs in first innings', innings=1)
manager.add_message('assistant', 'Strong batting display. Kohli scored 95.', innings=1)
manager.add_message('user', 'Australia batting now, targeting 250+', innings=2)
context = manager.get_context_for_agent()
print(f"Optimized context tokens: {len(str(context))}")
